import type { RepositoryBookmark } from '@/api';
import { A } from '@solidjs/router';
import { type ComponentProps, createMemo, createSignal } from 'solid-js';
import { Button } from './atoms';
import { DeleteIcon } from './icons';

interface BookmarkComponentProps extends ComponentProps<'div'> {
	bookmark: RepositoryBookmark;
	indent: number;
	selected: () => string;
	setSelected: (id: string) => void;
	deleteBookmark?: (bookmarkId: string, parentFolderId: string) => void;
}

const getFaviconUrl = (url: string): string => {
	try {
		const urlObj = new URL(url);
		return `${urlObj.protocol}//${urlObj.hostname}/favicon.ico`;
	} catch {
		return '';
	}
};

export default function BookmarkComponent(props: BookmarkComponentProps) {
	const faviconUrl = createMemo(() => getFaviconUrl(props.bookmark.link || ''));
	const [isDragging, setIsDragging] = createSignal(false);

	const handleDragStart = (e: DragEvent) => {
		setIsDragging(true);
		e.dataTransfer!.setData(
			'text/plain',
			JSON.stringify({
				type: 'bookmark',
				id: props.bookmark.id,
				name: props.bookmark.name,
				link: props.bookmark.link,
			}),
		);
		e.dataTransfer!.effectAllowed = 'move';
	};

	const handleDragEnd = () => {
		setIsDragging(false);
	};
	return (
		<div
			class={`flex items-center justify-between py-2 px-3 bg-white/20 backdrop-blur-md border border-white/30 text-white hover:bg-white/30 rounded-xl shadow-lg hover:shadow-xl transition-all duration-300 shadow-slate-900/20 ease-out w-64 hover:scale-105 active:scale-95 hover:border-white/50 ${isDragging() ? 'opacity-50' : ''}`}
			draggable={true}
			onDragStart={handleDragStart}
			onDragEnd={handleDragEnd}
			onClick={(e) => e.stopPropagation()}
		>
			<A
				class="flex flex-1 items-center cursor-pointer"
				href={props.bookmark.link || ''}
				rel="noopener noreferrer"
				target="_blank"
			>
				{faviconUrl() && (
					<img
						src={faviconUrl()}
						alt="favicon"
						class="w-4 h-4 mr-2 rounded-sm"
						onError={(e) => {
							// Hide favicon if it fails to load
							(e.target as HTMLImageElement).style.display = 'none';
						}}
					/>
				)}
				<span class="text-base font-bold">{props.bookmark.name}</span>
			</A>
			{props.deleteBookmark && (
				<Button
					variant="danger"
					class="p-1 ml-2 text-xs"
					onClick={(e) => {
						e.preventDefault();
						e.stopPropagation();
						if (
							props.deleteBookmark &&
							props.bookmark.id &&
							props.bookmark.folderId
						) {
							props.deleteBookmark(props.bookmark.id, props.bookmark.folderId);
						}
					}}
				>
					<DeleteIcon />
				</Button>
			)}
		</div>
	);
}
